  2	import { SyncAltIcon } from '@patternfly/react-icons';
  3	import React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { useParams } from 'react-router-dom-v5-compat';
  6	import {
  7	  availableDevConsoleAttributes,
  8	  filtersFromQuery,
  9	  initialAvailableAttributes,
 10	  queryFromFilters,
 11	} from '../attribute-filters';
 12	import { CenteredContainer } from '../components/centered-container';
 13	import { Filters } from '../components/filters/filter.types';
 14	import { LogsHistogram } from '../components/logs-histogram';
 15	import { LogsMetrics } from '../components/logs-metrics';
 16	import { LogsTable } from '../components/logs-table';
 17	import { LogsToolbar } from '../components/logs-toolbar';
 18	import { RefreshIntervalDropdown } from '../components/refresh-interval-dropdown';
 19	import { TimeRangeDropdown } from '../components/time-range-dropdown';
 20	import { TimezoneDropdown } from '../components/timezone-dropdown';
 21	import { ToggleHistogramButton } from '../components/toggle-histogram-button';
 22	import { downloadCSV } from '../download-csv';
 23	import { LogsConfigProvider, useLogsConfig } from '../hooks/LogsConfigProvider';
 24	import { useLogs } from '../hooks/useLogs';
 25	import { defaultQueryFromTenant, useURLState } from '../hooks/useURLState';
 26	import { Direction, isMatrixResult } from '../logs.types';
 27	import { TestIds } from '../test-ids';
 28	import { getInitialTenantFromNamespace } from '../value-utils';
 29	
 30	/*
 31	This comment creates an entry in the translations catalogue for console extensions
 32	
 33	t('plugin__logging-view-plugin~Logs')
 34	
 35	*/
 36	
 37	interface LogsDevPageProps {
 38	  ns?: string;
 39	}
 40	
 41	const LogsDevPage: React.FC<LogsDevPageProps> = ({ ns: namespaceFromProps }) => {
 42	  const { t } = useTranslation('plugin__logging-view-plugin');
 43	  const { ns: namespaceFromParams } = useParams<{ ns: string }>();
 44	  const namespace = namespaceFromParams || namespaceFromProps;
 45	  const [isHistogramVisible, setIsHistogramVisible] = React.useState(false);
 46	  let tenant = getInitialTenantFromNamespace(namespace);
 47	
 48	  const { config, configLoaded } = useLogsConfig();
 49	
 50	  const {
 51	    histogramData,
 52	    histogramError,
 53	    isLoadingLogsData,
 54	    isLoadingMoreLogsData,
 55	    isLoadingHistogramData,
 56	    isStreaming,
 57	    logsData,
 58	    logsError,
 59	    volumeData,
 60	    isLoadingVolumeData,
 61	    volumeError,
 62	    showVolumeGraph,
 63	    getLogs,
 64	    getVolume,
 65	    getMoreLogs,
 66	    hasMoreLogsData,
 67	    getHistogram,
 68	    toggleStreaming,
 69	  } = useLogs();
 70	
 71	  const {
 72	    query,
 73	    setQueryInURL,
 74	    schema,
 75	    setSchemaInURL,
 76	    areResourcesShown,
 77	    setShowResourcesInURL,
 78	    areStatsShown,
 79	    setShowStatsInURL,
 80	    filters,
 81	    setFilters,
 82	    setTimeRangeInURL,
 83	    timeRange,
 84	    interval,
 85	    direction,
 86	    setDirectionInURL,
 87	    timezone,
 88	    setTimezoneInURL,
 89	    attributes,
 90	  } = useURLState({
 91	    defaultTenant: tenant,
 92	    getAttributes: ({ config: c, schema: s }) =>
 93	      availableDevConsoleAttributes(getInitialTenantFromNamespace(namespace), c, s),
 94	    attributesDependencies: [namespace],
 95	  });
 96	
 97	  const handleToggleStreaming = () => {
 98	    toggleStreaming({ query, schema });
 99	  };
100	
101	  const handleLoadMoreData = (lastTimestamp: number) => {
102	    if (!isLoadingMoreLogsData) {
103	      getMoreLogs({ lastTimestamp, query, namespace, direction, schema });
104	    }
105	  };
106	
107	  const handleSortByDate = (directionValue?: Direction) => {
108	    setDirectionInURL(directionValue);
109	  };
110	
111	  const runQuery = ({ queryToUse }: { queryToUse?: string } = {}) => {
112	    getLogs({
113	      query: queryToUse ?? query,
114	      timeRange,
115	      direction,
116	      tenant,
117	      schema,
118	    });
119	
120	    if (isHistogramVisible) {
121	      getHistogram({ query: queryToUse ?? query, timeRange, tenant, schema });
122	    }
123	  };
124	
125	  const runVolume = () => {
126	    getVolume({ query, tenant, namespace, timeRange, schema });
127	  };
128	
129	  const handleFiltersChange = (selectedFilters?: Filters) => {
130	    setFilters(selectedFilters);
131	    updateQuery(selectedFilters, tenant);
132	  };
133	
134	  const handleQueryChange = (queryFromInput: string) => {
135	    setQueryInURL(queryFromInput);
136	
137	    const updatedFilters = filtersFromQuery({
138	      query: queryFromInput,
139	      attributes: initialAvailableAttributes(schema),
140	      schema: schema,
141	    });
142	
143	    setFilters(updatedFilters);
144	  };
145	
146	  const handleRefreshClick = () => {
147	    runQuery();
148	  };
149	
150	  const updateQuery = (selectedFilters?: Filters, selectedTenant?: string): string => {
151	    const hasNoSelectedfilters = !selectedFilters || Object.keys(selectedFilters).length === 0;
152	
153	    if (hasNoSelectedfilters) {
154	      const updatedQuery = queryFromFilters({
155	        existingQuery: defaultQueryFromTenant({ tenant: selectedTenant, schema }),
156	        filters: { namespace: new Set(namespace ? [namespace] : []) },
157	        attributes: initialAvailableAttributes(schema),
158	        tenant: selectedTenant,
159	        schema,
160	      });
161	
162	      setQueryInURL(updatedQuery);
163	
164	      return updatedQuery;
165	    } else {
166	      const updatedQuery = queryFromFilters({
167	        existingQuery: query,
168	        filters: selectedFilters,
169	        attributes: initialAvailableAttributes(schema),
170	        tenant: selectedTenant,
171	        schema,
172	      });
173	
174	      setQueryInURL(updatedQuery);
175	
176	      return updatedQuery;
177	    }
178	  };
179	
180	  React.useEffect(() => {
181	    if (!configLoaded) {
182	      return;
183	    }
184	
185	    tenant = getInitialTenantFromNamespace(namespace);
186	
187	    const queryToUse = updateQuery(filters, tenant);
188	
189	    runQuery({ queryToUse });
190	  }, [timeRange, isHistogramVisible, direction, configLoaded]);
191	
192	  React.useEffect(() => {
193	    if (!configLoaded) {
194	      return;
195	    }
196	
197	    tenant = getInitialTenantFromNamespace(namespace);
198	
199	    const filtersWithNamespace = filters ?? {};
200	
201	    filtersWithNamespace['namespace'] = new Set(namespace ? [namespace] : []);
202	    const queryToUse = updateQuery(filtersWithNamespace, tenant);
203	
204	    runQuery({ queryToUse });
205	  }, [namespace, configLoaded]);
206	
207	  const isQueryEmpty = query === '';
208	  const isNamespaceFilterEmpty =
209	    filters?.['namespace'] === undefined || filters['namespace'].size === 0;
210	  const isRunQueryDisabled = isQueryEmpty || isNamespaceFilterEmpty;
211	
212	  const resultIsMetric = isMatrixResult(logsData?.data);
213	
214	  React.useEffect(() => {
215	    if (resultIsMetric) {
216	      setIsHistogramVisible(false);
217	    }
218	  }, [resultIsMetric]);
219	
220	  return (
221	    <PageSection>
222	      <Grid hasGutter>
223	        <Flex justifyContent={{ default: 'justifyContentFlexEnd' }}>
224	          <Flex>
225	            <ToggleHistogramButton
226	              isToggled={isHistogramVisible}
227	              onToggle={() => setIsHistogramVisible(!isHistogramVisible)}
228	              data-test={TestIds.ToggleHistogramButton}
229	              isDisabled={resultIsMetric}
230	            />
231	            <TimeRangeDropdown
232	              value={timeRange}
233	              onChange={setTimeRangeInURL}
234	              isDisabled={isRunQueryDisabled}
235	              timezone={timezone}
236	            />
237	            {config.showTimezoneSelector && (
238	              <TimezoneDropdown
239	                value={timezone}
240	                onChange={setTimezoneInURL}
241	                isDisabled={isQueryEmpty}
242	              />
243	            )}
244	            <RefreshIntervalDropdown onRefresh={runQuery} isDisabled={isRunQueryDisabled} />
245	            <Tooltip content={<div>Refresh</div>}>
246	              <Button
247	                onClick={handleRefreshClick}
248	                aria-label="Refresh"
249	                variant="secondary"
250	                data-test={TestIds.SyncButton}
251	                isDisabled={isRunQueryDisabled}
252	              >
253	                <SyncAltIcon />
254	              </Button>
255	            </Tooltip>
256	          </Flex>
257	        </Flex>
258	
259	        {isHistogramVisible && !resultIsMetric && (
260	          <LogsHistogram
261	            histogramData={histogramData}
262	            timeRange={timeRange}
263	            interval={interval}
264	            isLoading={isLoadingHistogramData}
265	            error={histogramError}
266	            onChangeTimeRange={setTimeRangeInURL}
267	            timezone={timezone}
268	          />
269	        )}
270	
271	        <LogsToolbar
272	          query={query}
273	          onQueryChange={handleQueryChange}
274	          onQueryRun={runQuery}
275	          onVolumeRun={runVolume}
276	          invalidQueryErrorMessage={
277	            isNamespaceFilterEmpty ? t('Please select a namespace') : undefined
278	          }
279	          isStreaming={isStreaming}
280	          onStreamingToggle={handleToggleStreaming}
281	          enableStreaming={config.isStreamingEnabledInDefaultPage}
282	          showResources={areResourcesShown}
283	          onShowResourcesToggle={setShowResourcesInURL}
284	          showStats={areStatsShown}
285	          onShowStatsToggle={setShowStatsInURL}
286	          enableTenantDropdown={false}
287	          isDisabled={isRunQueryDisabled}
288	          attributeList={attributes}
289	          filters={filters}
290	          onFiltersChange={handleFiltersChange}
291	          onDownloadCSV={() => downloadCSV(logsData)}
292	          schema={schema}
293	          onSchemaSelect={setSchemaInURL}
294	        />
295	
296	        {isLoadingLogsData ? (
297	          <CenteredContainer>{t('Loading...')}</CenteredContainer>
298	        ) : showVolumeGraph ? (
299	          <Card>
300	            <CardBody>
301	              <LogsMetrics
302	                logsData={volumeData}
303	                timeRange={timeRange}
304	                isLoading={isLoadingVolumeData}
305	                error={volumeError}
306	                height={350}
307	                timezone={timezone}
308	                displayLegendTable
309	              />
310	            </CardBody>
311	          </Card>
312	        ) : resultIsMetric ? (
313	          <Card>
314	            <CardBody>
315	              <LogsMetrics
316	                logsData={logsData}
317	                timeRange={timeRange}
318	                isLoading={isLoadingLogsData}
319	                error={logsError}
320	                height={350}
321	                timezone={timezone}
322	                displayLegendTable
323	              />
324	            </CardBody>
325	          </Card>
326	        ) : (
327	          <LogsTable
328	            logsData={logsData}
329	            onLoadMore={handleLoadMoreData}
330	            onSortByDate={handleSortByDate}
331	            isLoading={isLoadingLogsData}
332	            isLoadingMore={isLoadingMoreLogsData}
333	            hasMoreLogsData={hasMoreLogsData}
334	            direction={direction}
335	            showResources={areResourcesShown}
336	            showStats={areStatsShown}
337	            isStreaming={isStreaming}
338	            error={logsError}
339	            timezone={timezone}
340	            hasNamespaceFilter={Boolean(filters?.namespace?.size)}
341	            schema={schema}
342	          />
343	        )}
344	      </Grid>
345	    </PageSection>
346	  );
347	};
