349	const LogsDevPageWrapper: React.FC<LogsDevPageProps> = (props) => {
350	  return (
351	    <LogsConfigProvider>
352	      <LogsDevPage {...props} />
353	    </LogsConfigProvider>
354	  );
355	};
356	
357	export default LogsDevPageWrapper;

